  body += p("Elle survient \u00e0 la suite d\u2019une sollicitation du client qui rencontre des difficult\u00e9s de connexion au r\u00e9seau mobile.",{sz:22});
  body += pEmpty(80);

  // ═══ 2. OUTILS ═══════════════════════════════════════════════════════════
  body += heading1('2','Outil de mesures / Tests', 3);
  body += p('NETWORK CELL INFO LITE', {sz:22, bold:true, align:'center'});
  body += p("Note\u00a0: A chaque point de mesure nous relevons \u00e0 minima le niveau d\u2019affaiblissement que re\u00e7oit le terminal.",{sz:22});
  body += p("Nous recommandons de r\u00e9aliser un speedtest (4G) \u00e0 l\u2019ext\u00e9rieur de la soci\u00e9t\u00e9 audit\u00e9e puis un relev\u00e9 \u00e0 l\u2019endroit o\u00f9 le niveau est le plus faible ainsi qu\u2019\u00e0 l\u2019endroit o\u00f9 les champs sont les plus forts en int\u00e9rieur.",{sz:22});
  if ((data.outils||{}).notes) body += p(data.outils.notes,{sz:22});

  // Jauges: image gauche (5.9cm) + speedtest droite (11.3cm) côte à côte
